import { create } from "zustand";

interface Store {
  // barcode: string[];
  addBy: number;
  addItem: () => void;
  // addItem: (barcode: string) => void;
}

export const usePOSStore = create<Store>()((set) => ({
  addBy: 1,
  addItem: () => set((state) => ({ addBy: state.addBy + 1 })),
  // barcode: [],
  // addItem: (barcodes) => set((state) => ({ barcode: [...state.barcode, barcodes] })),
}));

interface IkycStore {
  value: string;
  selected: (newValue: string) => void;
}

export const kycStore = create<IkycStore>()((set) => ({
  value: "Yes",
  selected: (newValue) => set({ value: newValue }),
}));
