import { z } from "zod";

export const productSchema = z.object({
  productName: z.string().trim().min(1, "Product name is required"),
  productBarcode: z.string().trim().min(1, "Barcode is required"),
  quantity: z.number().int().positive().min(1, "Quantity must be at least 1"),
  price: z
    .number()
    .int()
    .positive()
    .min(0.01, "Price should be greater than 0"),
});

export const barcodeScheme = z.object({
  barcodeString: z.string().trim().min(1, "This field only accepts text"),
});

export const kycScheme = z.object({
  citizen: z.enum(["Yes", "No"], { message: "Please choose one" }),
  reside: z.enum(["Yes", "No"], { message: "Please choose one" }),
  id: z.enum(
    [
      "Driver License",
      "Passport",
      "PhilSys (Identification System) ID",
      "SSS(Social Security System) ID",
      "TIN (OLD Version)",
      "TIN (Tax Identification Number)",
      "UMID (Unified Multi-Purpose Identity Card)",
    ],
    { message: "Please choose one ID" }
  ),
});
